const body = $input.first().json.body;
let mensajes = [];

if (body && body.entry) {
  for (const entry of body.entry) {
    if (entry.messaging) {
      for (const msg of entry.messaging) {
        if (msg.message && msg.message.text) {
          mensajes.push({
            tipo: 'DM',
            senderId: msg.sender.id,
            texto: msg.message.text,
            timestamp: msg.timestamp,
            messageId: msg.message.mid
          });
        }
      }
    }
    if (entry.changes) {
      for (const change of entry.changes) {
        if (change.field === 'comments' && change.value && change.value.text) {
          mensajes.push({
            tipo: 'COMENTARIO',
            senderId: change.value.from ? change.value.from.id : '',
            senderName: change.value.from ? change.value.from.name : 'Usuario',
            texto: change.value.text,
            timestamp: change.value.timestamp,
            commentId: change.value.id,
            mediaId: change.value.media ? change.value.media.id : ''
          });
        }
      }
    }
  }
}

if (mensajes.length === 0) {
  return [{ json: { skip: true } }];
}

return mensajes.map(function(m) { return { json: m }; });

