const aiResp = $input.first().json;
const raw = (aiResp.choices && aiResp.choices[0] && aiResp.choices[0].message)
  ? aiResp.choices[0].message.content.trim().toUpperCase()
  : 'RECLAMO';

const clasificacion = raw === 'AGRESIVO' ? 'AGRESIVO' : 'RECLAMO';
const origen = $('Preparar Texto').first().json;

return [{
  json: {
    tipo: origen.tipo,
    senderId: origen.senderId,
    texto: origen.texto,
    clasificacion: clasificacion,
    procesadoEn: new Date().toISOString()
  }
}];

